import{_ as a,o as t,c as s,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"WebChat","description":"","frontmatter":{"summary":"How the mac app embeds the gateway WebChat and how to debug it","read_when":["Debugging mac WebChat view or loopback port"],"title":"WebChat"},"headers":[],"relativePath":"platforms/mac/webchat.md","filePath":"platforms/mac/webchat.md","lastUpdated":null}'),i={name:"platforms/mac/webchat.md"};function n(c,e,d,l,r,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="webchat-macos-app" tabindex="-1"><a class="header-anchor" href="#webchat-macos-app">#</a> WebChat (macOS app)</h1><p>The macOS menu bar app embeds the WebChat UI as a native SwiftUI view. It connects to the Gateway and defaults to the <strong>main session</strong> for the selected agent (with a session switcher for other sessions).</p><ul><li><strong>Local mode</strong>: connects directly to the local Gateway WebSocket.</li><li><strong>Remote mode</strong>: forwards the Gateway control port over SSH and uses that tunnel as the data plane.</li></ul><h2 id="launch-debugging" tabindex="-1"><a class="header-anchor" href="#launch-debugging">#</a> Launch &amp; debugging</h2><ul><li><p>Manual: Lobster menu → “Open Chat”.</p></li><li><p>Auto‑open for testing:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dist/OpenSoul.app/Contents/MacOS/OpenSoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --webchat</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Logs: <code>./scripts/opensoul-log.sh</code> (subsystem <code>ai.opensoul</code>, category <code>WebChatSwiftUI</code>).</p></li></ul><h2 id="how-it-s-wired" tabindex="-1"><a class="header-anchor" href="#how-it-s-wired">#</a> How it’s wired</h2><ul><li>Data plane: Gateway WS methods <code>chat.history</code>, <code>chat.send</code>, <code>chat.abort</code>, <code>chat.inject</code> and events <code>chat</code>, <code>agent</code>, <code>presence</code>, <code>tick</code>, <code>health</code>.</li><li>Session: defaults to the primary session (<code>main</code>, or <code>global</code> when scope is global). The UI can switch between sessions.</li><li>Onboarding uses a dedicated session to keep first‑run setup separate.</li></ul><h2 id="security-surface" tabindex="-1"><a class="header-anchor" href="#security-surface">#</a> Security surface</h2><ul><li>Remote mode forwards only the Gateway WebSocket control port over SSH.</li></ul><h2 id="known-limitations" tabindex="-1"><a class="header-anchor" href="#known-limitations">#</a> Known limitations</h2><ul><li>The UI is optimized for chat sessions (not a full browser sandbox).</li></ul>',11)])])}const b=a(i,[["render",n]]);export{u as __pageData,b as default};
